// src/nodes/deleteNode.js
import React, { useCallback } from "react";
import "./node.css";

export const DeleteNode = ({ data }) => {
  const handleDelete = useCallback(() => {
    // defensive checks and logs for debugging
    console.log("[DeleteNode] clicked", { incoming: data?.incoming, onDelete: data?.onDelete });

    if (!data) {
      console.warn("[DeleteNode] no data prop provided");
      return;
    }

    const { incoming, onDelete } = data;

    if (!incoming) {
      console.warn("[DeleteNode] no incoming node to delete");
      return;
    }

    if (typeof onDelete !== "function") {
      console.error("[DeleteNode] data.onDelete is not a function", onDelete);
      return;
    }

    // optional confirmation to avoid accidental deletes
    const ok = window.confirm(`Delete node ${incoming} and its edges?`);
    if (!ok) return;

    onDelete(incoming);
  }, [data]);

  return (
    <div className="vs-node delete-node">
      <div className="vs-node-header">Delete Node</div>
      <p>Incoming: {data?.incoming || "None"}</p>
      <button onClick={handleDelete}>Delete Incoming</button>
    </div>
  );
};
